// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "@openzeppelin/contracts/access/Ownable.sol";
import "./InsuranceNFT.sol";
import "./InsurancePool.sol";
import "./RiskOracle.sol";

contract InsuranceManager is Ownable {
    InsuranceNFT public immutable insuranceNFT;
    InsurancePool public immutable insurancePool;
    RiskOracle public immutable riskOracle;

    address public liquidationEngine;

    uint256 public coverageFactorBps = 5000; // 50%
    uint256 public maxCoverageBps = 6000; // 60%
    uint256 public minLockPeriod = 1 hours;

    mapping(bytes32 => uint256) public recordedLiquidationLoss;

    event LiquidationEngineUpdated(address indexed liquidationEngine);
    event CoverageParamsUpdated(uint256 coverageFactorBps, uint256 maxCoverageBps, uint256 minLockPeriod);
    event PolicyPurchased(address indexed borrower, uint256 indexed policyId, uint256 indexed loanId, uint256 premium, uint256 coverageAmount);
    event LiquidationRecorded(address indexed borrower, uint256 indexed loanId, uint256 lossAmount);
    event PolicyClaimed(address indexed borrower, uint256 indexed policyId, uint256 payoutAmount);

    constructor(address nft, address pool, address oracle) {
        require(nft != address(0) && pool != address(0) && oracle != address(0), "Invalid address");
        insuranceNFT = InsuranceNFT(nft);
        insurancePool = InsurancePool(pool);
        riskOracle = RiskOracle(oracle);
    }

    function setLiquidationEngine(address engine) external onlyOwner {
        require(engine != address(0), "Invalid engine");
        liquidationEngine = engine;
        emit LiquidationEngineUpdated(engine);
    }

    function setCoverageParams(uint256 _coverageFactorBps, uint256 _maxCoverageBps, uint256 _minLockPeriod) external onlyOwner {
        require(_coverageFactorBps <= 10000, "Invalid coverage factor");
        require(_maxCoverageBps <= 10000, "Invalid max coverage");

        coverageFactorBps = _coverageFactorBps;
        maxCoverageBps = _maxCoverageBps;
        minLockPeriod = _minLockPeriod;

        emit CoverageParamsUpdated(_coverageFactorBps, _maxCoverageBps, _minLockPeriod);
    }

    function quotePremium(address borrower, uint256 loanId, uint256 coverageAmount) public view returns (uint256 premium, uint256 riskBps) {
        require(borrower != address(0), "Invalid borrower");
        require(coverageAmount > 0, "Invalid coverage");

        riskBps = riskOracle.getRiskBps(borrower, loanId);
        require(riskBps > 0, "Risk unavailable");

        premium = (coverageAmount * riskBps * coverageFactorBps) / 100000000;
        if (premium == 0) {
            premium = 1;
        }
    }

    function buyPolicy(uint256 loanId, uint256 loanAmount, uint256 coverageAmount, uint256 duration) external returns (uint256 policyId, uint256 premium) {
        require(duration >= minLockPeriod, "Duration too short");
        require(coverageAmount > 0, "Coverage required");
        require(loanAmount > 0, "Loan amount required");

        uint256 maxCoverage = (loanAmount * maxCoverageBps) / 10000;
        require(coverageAmount <= maxCoverage, "Coverage exceeds cap");

        uint256 riskBps;
        (premium, riskBps) = quotePremium(msg.sender, loanId, coverageAmount);

        insurancePool.collectPremium(msg.sender, premium);

        uint256 expiry = block.timestamp + duration;
        policyId = insuranceNFT.mintPolicy(
            msg.sender,
            loanId,
            coverageAmount,
            premium,
            riskBps,
            expiry
        );

        emit PolicyPurchased(msg.sender, policyId, loanId, premium, coverageAmount);
    }

    function recordLiquidation(address borrower, uint256 loanId, uint256 lossAmount) external {
        require(msg.sender == liquidationEngine || msg.sender == owner(), "Unauthorized caller");
        require(borrower != address(0), "Invalid borrower");
        require(lossAmount > 0, "Invalid loss");

        bytes32 key = keccak256(abi.encodePacked(borrower, loanId));
        recordedLiquidationLoss[key] = lossAmount;

        emit LiquidationRecorded(borrower, loanId, lossAmount);
    }

    function claimPolicy(uint256 policyId) external returns (uint256 payoutAmount) {
        require(insuranceNFT.ownerOf(policyId) == msg.sender, "Not policy owner");

        InsuranceNFT.Policy memory policy = insuranceNFT.getPolicy(policyId);
        require(policy.isActive, "Policy inactive");
        require(!policy.isClaimed, "Already claimed");
        require(block.timestamp <= policy.expiry, "Policy expired");

        bytes32 key = keccak256(abi.encodePacked(policy.borrower, policy.loanId));
        uint256 lossAmount = recordedLiquidationLoss[key];
        require(lossAmount > 0, "No liquidation record");

        payoutAmount = lossAmount;
        if (payoutAmount > policy.coverageAmount) {
            payoutAmount = policy.coverageAmount;
        }

        insuranceNFT.markPolicyClaimed(policyId);
        insurancePool.payoutClaim(msg.sender, payoutAmount);

        delete recordedLiquidationLoss[key];

        emit PolicyClaimed(msg.sender, policyId, payoutAmount);
    }
}

contracts/InsuranceNFT.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract InsuranceNFT is ERC721, Ownable {
    struct Policy {
        address borrower;
        uint256 loanId;
        uint256 coverageAmount;
        uint256 premiumPaid;
        uint256 riskBps;
        uint256 startTime;
        uint256 expiry;
        bool isClaimed;
        bool isActive;
    }

    uint256 public nextPolicyId;
    address public manager;

    mapping(uint256 => Policy) private _policies;

    event ManagerUpdated(address indexed manager);
    event PolicyMinted(uint256 indexed policyId, address indexed borrower, uint256 indexed loanId, uint256 coverageAmount, uint256 premiumPaid, uint256 expiry);
    event PolicyClaimed(uint256 indexed policyId, address indexed borrower);
    event PolicyExpired(uint256 indexed policyId);

    modifier onlyManager() {
        require(msg.sender == manager, "Only manager");
        _;
    }

    constructor() ERC721("Liquidation Insurance Policy", "LIP") {}

    function setManager(address _manager) external onlyOwner {
        require(_manager != address(0), "Invalid manager");
        manager = _manager;
        emit ManagerUpdated(_manager);
    }

    function mintPolicy(
        address borrower,
        uint256 loanId,
        uint256 coverageAmount,
        uint256 premiumPaid,
        uint256 riskBps,
        uint256 expiry
    ) external onlyManager returns (uint256 policyId) {
        require(borrower != address(0), "Invalid borrower");
        require(coverageAmount > 0, "Invalid coverage");
        require(expiry > block.timestamp, "Invalid expiry");

        policyId = ++nextPolicyId;
        _safeMint(borrower, policyId);

        _policies[policyId] = Policy({
            borrower: borrower,
            loanId: loanId,
            coverageAmount: coverageAmount,
            premiumPaid: premiumPaid,
            riskBps: riskBps,
            startTime: block.timestamp,
            expiry: expiry,
            isClaimed: false,
            isActive: true
        });

        emit PolicyMinted(policyId, borrower, loanId, coverageAmount, premiumPaid, expiry);
    }

    function markPolicyClaimed(uint256 policyId) external onlyManager {
        Policy storage policy = _policies[policyId];
        require(policy.isActive, "Policy inactive");
        require(!policy.isClaimed, "Already claimed");

        policy.isClaimed = true;
        policy.isActive = false;

        emit PolicyClaimed(policyId, policy.borrower);
    }

    function markPolicyExpired(uint256 policyId) external onlyManager {
        Policy storage policy = _policies[policyId];
        require(policy.isActive, "Policy inactive");
        require(block.timestamp > policy.expiry, "Not expired");

        policy.isActive = false;
        emit PolicyExpired(policyId);
    }

    function getPolicy(uint256 policyId) external view returns (Policy memory) {
        return _policies[policyId];
    }

    function isPolicyActive(uint256 policyId) external view returns (bool) {
        Policy memory policy = _policies[policyId];
        return policy.isActive && !policy.isClaimed && block.timestamp <= policy.expiry;
    }
}

contracts/InsurancePool.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract InsurancePool is ReentrancyGuard, Ownable {
    IERC20 public immutable stableToken;
    address public manager;

    mapping(address => uint256) public liquidityProvided;
    uint256 public totalLiquidity;

    event ManagerUpdated(address indexed manager);
    event LiquidityDeposited(address indexed provider, uint256 amount);
    event LiquidityWithdrawn(address indexed provider, uint256 amount);
    event PremiumCollected(address indexed payer, uint256 amount);
    event ClaimPaid(address indexed recipient, uint256 amount);

    modifier onlyManager() {
        require(msg.sender == manager, "Only manager");
        _;
    }

    constructor(address stableTokenAddress) {
        require(stableTokenAddress != address(0), "Invalid token");
        stableToken = IERC20(stableTokenAddress);
    }

    function setManager(address _manager) external onlyOwner {
        require(_manager != address(0), "Invalid manager");
        manager = _manager;
        emit ManagerUpdated(_manager);
    }

    function depositLiquidity(uint256 amount) external nonReentrant {
        require(amount > 0, "Invalid amount");

        stableToken.transferFrom(msg.sender, address(this), amount);
        liquidityProvided[msg.sender] += amount;
        totalLiquidity += amount;

        emit LiquidityDeposited(msg.sender, amount);
    }

    function withdrawLiquidity(uint256 amount) external nonReentrant {
        require(amount > 0, "Invalid amount");
        require(liquidityProvided[msg.sender] >= amount, "Insufficient LP balance");
        require(amount <= stableToken.balanceOf(address(this)), "Insufficient pool balance");

        liquidityProvided[msg.sender] -= amount;
        totalLiquidity -= amount;

        stableToken.transfer(msg.sender, amount);
        emit LiquidityWithdrawn(msg.sender, amount);
    }

    function collectPremium(address payer, uint256 amount) external onlyManager nonReentrant {
        require(payer != address(0), "Invalid payer");
        require(amount > 0, "Invalid amount");

        stableToken.transferFrom(payer, address(this), amount);
        totalLiquidity += amount;

        emit PremiumCollected(payer, amount);
    }

    function payoutClaim(address recipient, uint256 amount) external onlyManager nonReentrant {
        require(recipient != address(0), "Invalid recipient");
        require(amount > 0, "Invalid amount");
        require(amount <= stableToken.balanceOf(address(this)), "Pool insolvency");

        if (totalLiquidity >= amount) {
            totalLiquidity -= amount;
        } else {
            totalLiquidity = 0;
        }

        stableToken.transfer(recipient, amount);
        emit ClaimPaid(recipient, amount);
    }

    function poolBalance() external view returns (uint256) {
        return stableToken.balanceOf(address(this));
    }
}

contracts/RiskOracle.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title RiskOracle
 * @dev Smart Risk Prediction Engine
 * Calculates liquidation risk and dynamic collateral requirements
 */
contract RiskOracle is Ownable {
    // Asset risk and collateral ratio storage
    struct AssetRisk {
        uint256 riskScore;           // 0-100 (percentage, divided by 100 = bps)
        uint256 volatilityScore;     // 0-100
        uint256 requiredCollateralRatioBps; // in basis points (e.g., 14000 = 140%)
        uint256 updatedAt;
        bool isActive;
    }

    // Mapping of asset address to risk data
    mapping(address => AssetRisk) public assetRisks;

    // Legacy risk scores for borrowers (kept for backward compatibility)
    mapping(address => mapping(uint256 => uint256)) private _borrowerRiskScores;

    event AssetRiskUpdated(
        address indexed asset,
        uint256 riskScore,
        uint256 volatilityScore,
        uint256 requiredCollateralRatioBps
    );
    event BorrowerRiskScoreUpdated(address indexed borrower, uint256 indexed loanId, uint256 riskBps);

    constructor() {
        // Initialize default risks for common assets
        // Formula: (LTV × 0.5) + (Volatility × 0.3) + (LiquidityRisk × 0.2)

        // Mock ETH: Low volatility
        _initAssetRisk(address(0x1), 800,  2000, 14000);  // 8% risk, 20% volatility, 140% ratio

        // Mock BNB: Medium volatility
        _initAssetRisk(address(0x2), 1200, 4000, 16000);  // 12% risk, 40% volatility, 160% ratio

        // Mock Meme: High volatility
        _initAssetRisk(address(0x3), 3500, 8000, 22000);  // 35% risk, 80% volatility, 220% ratio
    }

    function _initAssetRisk(
        address asset,
        uint256 riskScore,
        uint256 volatilityScore,
        uint256 requiredCollateralRatioBps
    ) internal {
        assetRisks[asset] = AssetRisk({
            riskScore: riskScore,
            volatilityScore: volatilityScore,
            requiredCollateralRatioBps: requiredCollateralRatioBps,
            updatedAt: block.timestamp,
            isActive: true
        });
    }

    /**
     * @dev Set risk for a specific asset (owner only)
     * Updates: risk score, volatility, and required collateral ratio
     */
    function setAssetRisk(
        address asset,
        uint256 riskScore,
        uint256 volatilityScore,
        uint256 requiredCollateralRatioBps
    ) external onlyOwner {
        require(asset != address(0), "Invalid asset");
        require(riskScore <= 10000, "Risk too high");
        require(volatilityScore <= 10000, "Volatility too high");
        require(requiredCollateralRatioBps >= 10000, "Ratio too low");

        assetRisks[asset] = AssetRisk({
            riskScore: riskScore,
            volatilityScore: volatilityScore,
            requiredCollateralRatioBps: requiredCollateralRatioBps,
            updatedAt: block.timestamp,
            isActive: true
        });

        emit AssetRiskUpdated(asset, riskScore, volatilityScore, requiredCollateralRatioBps);
    }

    /**
     * @dev Get complete risk data for an asset
     */
    function getAssetRisk(address asset)
        external
        view
        returns (
            uint256 riskScore,
            uint256 volatilityScore,
            uint256 requiredCollateralRatioBps
        )
    {
        AssetRisk memory risk = assetRisks[asset];

        // Return defaults if not set
        if (!risk.isActive) {
            return (1000, 2000, 14000);  // Default: 10% risk, 20% volatility, 140% ratio
        }

        return (risk.riskScore, risk.volatilityScore, risk.requiredCollateralRatioBps);
    }

    /**
     * @dev Get required collateral ratio for an asset
     * Used by LendingPool to validate borrow requests
     */
    function getRequiredCollateralRatio(address asset) external view returns (uint256) {
        AssetRisk memory risk = assetRisks[asset];
        if (!risk.isActive) {
            return 14000;  // Default 140%
        }
        return risk.requiredCollateralRatioBps;
    }

    /**
     * @dev Get risk score as percentage (0-10000)
     * For UI display
     */
    function getRiskScorePercent(address asset) external view returns (uint256) {
        AssetRisk memory risk = assetRisks[asset];
        if (!risk.isActive) {
            return 1000;  // Default 10%
        }
        return risk.riskScore;
    }

    /**
     * @dev Get volatility score
     * For UI display and risk indicators
     */
    function getVolatilityScore(address asset) external view returns (uint256) {
        AssetRisk memory risk = assetRisks[asset];
        if (!risk.isActive) {
            return 2000;  // Default 20%
        }
        return risk.volatilityScore;
    }

    /**
     * @dev Legacy function - set borrower-specific risk score
     * Kept for backward compatibility with insurance module
     */
    function setRiskScore(address borrower, uint256 loanId, uint256 riskBps) external onlyOwner {
        require(borrower != address(0), "Invalid borrower");
        require(riskBps <= 10000, "Risk too high");
        _borrowerRiskScores[borrower][loanId] = riskBps;
        emit BorrowerRiskScoreUpdated(borrower, loanId, riskBps);
    }

    /**
     * @dev Legacy function - get borrower risk score
     */
    function getRiskBps(address borrower, uint256 loanId) external view returns (uint256) {
        uint256 riskBps = _borrowerRiskScores[borrower][loanId];
        return riskBps > 0 ? riskBps : 1000;  // Default 10%
    }

    /**
     * @dev Legacy function - get borrower risk score
     */
    function getRiskScore(address borrower, uint256 loanId) external view returns (uint256 riskBps, uint256 updatedAt) {
        uint256 bps = _borrowerRiskScores[borrower][loanId];
        uint256 score = bps > 0 ? bps : 1000;
        return (score, block.timestamp);
    }

    /**
     * @dev Calculate healthy liquidation risk
     * Green: < 10%, Yellow: 10-25%, Red: > 25%
     */
    function getLiquidationRiskLevel(address asset) external view returns (string memory) {
        AssetRisk memory risk = assetRisks[asset];
        uint256 riskScore = risk.isActive ? risk.riskScore : 1000;

        if (riskScore < 1000) {
            return "GREEN";   // < 10%
        } else if (riskScore < 2500) {
            return "YELLOW";  // 10-25%
        } else {
            return "RED";     // > 25%
        }
    }
}

contracts/SmartCollateralVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title SmartCollateralVault
 * @dev Core collateral management contract for Web3 Credit & BNPL
 * Inspired by Compound Protocol & Lenfi Smart Contracts
 */
contract SmartCollateralVault is ReentrancyGuard, Ownable {
    // ==================== State Variables ====================

    // Collateral tracking
    mapping(address => mapping(address => uint256)) public collateralDeposits; // user => token => amount
    mapping(address => bool) public isCollateralSupported; // token => is supported

    // Debt tracking
    mapping(address => mapping(address => uint256)) public borrowedAmount; // user => token => amount
    mapping(address => uint256) public totalDebt; // token => total borrowed

    // Collateral ratios (in basis points, 10000 = 100%)
    uint256 public minCollateralRatio = 15000; // 150% default
    uint256 public liquidationThreshold = 12000; // 120%
    uint256 public liquidationBonus = 1000; // 10%

    // Supported collateral tokens
    address[] public supportedCollaterals;

    // Events
    event CollateralDeposited(address indexed user, address indexed token, uint256 amount);
    event CollateralWithdrawn(address indexed user, address indexed token, uint256 amount);
    event BorrowingInitiated(address indexed user, address indexed token, uint256 amount);
    event DebtRepaid(address indexed user, address indexed token, uint256 amount);
    event CollateralLiquidated(address indexed user, address indexed token, uint256 amount, address indexed liquidator);
    event CollateralAdded(address indexed token);
    event CollateralRemoved(address indexed token);

    // ==================== Constructor ====================

    constructor() {
        // Initializations
    }

    // ==================== Admin Functions ====================

    /**
     * @dev Add supported collateral token
     */
    function addCollateral(address token) external onlyOwner {
        require(token != address(0), "Invalid token address");
        require(!isCollateralSupported[token], "Token already supported");

        isCollateralSupported[token] = true;
        supportedCollaterals.push(token);

        emit CollateralAdded(token);
    }

    /**
     * @dev Remove collateral token from supported list
     */
    function removeCollateral(address token) external onlyOwner {
        require(isCollateralSupported[token], "Token not supported");

        isCollateralSupported[token] = false;

        // Remove from array
        for (uint256 i = 0; i < supportedCollaterals.length; i++) {
            if (supportedCollaterals[i] == token) {
                supportedCollaterals[i] = supportedCollaterals[supportedCollaterals.length - 1];
                supportedCollaterals.pop();
                break;
            }
        }

        emit CollateralRemoved(token);
    }

    /**
     * @dev Update collateral ratio
     */
    function setMinCollateralRatio(uint256 newRatio) external onlyOwner {
        require(newRatio > liquidationThreshold, "Ratio too low");
        minCollateralRatio = newRatio;
    }

    /**
     * @dev Update liquidation threshold
     */
    function setLiquidationThreshold(uint256 threshold) external onlyOwner {
        require(threshold < minCollateralRatio, "Invalid threshold");
        liquidationThreshold = threshold;
    }

    /**
     * @dev Update liquidation bonus
     */
    function setLiquidationBonus(uint256 bonus) external onlyOwner {
        require(bonus <= 5000, "Bonus too high"); // Max 50%
        liquidationBonus = bonus;
    }

    // ==================== User Functions ====================

    /**
     * @dev Deposit collateral
     */
    function depositCollateral(address token, uint256 amount) external nonReentrant {
        require(isCollateralSupported[token], "Token not supported");
        require(amount > 0, "Amount must be greater than 0");

        IERC20(token).transferFrom(msg.sender, address(this), amount);
        collateralDeposits[msg.sender][token] += amount;

        emit CollateralDeposited(msg.sender, token, amount);
    }

    /**
     * @dev Withdraw collateral (if health factor allows)
     */
    function withdrawCollateral(address token, uint256 amount) external nonReentrant {
        require(collateralDeposits[msg.sender][token] >= amount, "Insufficient collateral");
        require(amount > 0, "Amount must be greater than 0");

        collateralDeposits[msg.sender][token] -= amount;

        // Check health factor after withdrawal
        require(isHealthy(msg.sender), "Would violate collateral ratio");

        IERC20(token).transfer(msg.sender, amount);

        emit CollateralWithdrawn(msg.sender, token, amount);
    }

    /**
     * @dev Borrow against collateral
     */
    function borrow(address collateralToken, address borrowToken, uint256 borrowAmount) 
        external 
        nonReentrant 
    {
        require(isCollateralSupported[collateralToken], "Collateral token not supported");
        require(collateralDeposits[msg.sender][collateralToken] > 0, "No collateral deposited");
        require(borrowAmount > 0, "Borrow amount must be greater than 0");

        borrowedAmount[msg.sender][borrowToken] += borrowAmount;
        totalDebt[borrowToken] += borrowAmount;

        // Check health factor
        require(isHealthy(msg.sender), "Would violate collateral ratio");

        // Transfer borrowed tokens (would need a lending pool)
        IERC20(borrowToken).transfer(msg.sender, borrowAmount);

        emit BorrowingInitiated(msg.sender, borrowToken, borrowAmount);
    }

    /**
     * @dev Repay borrowed amount
     */
    function repay(address borrowToken, uint256 amount) external nonReentrant {
        require(borrowedAmount[msg.sender][borrowToken] >= amount, "Repay amount too high");
        require(amount > 0, "Amount must be greater than 0");

        IERC20(borrowToken).transferFrom(msg.sender, address(this), amount);

        borrowedAmount[msg.sender][borrowToken] -= amount;
        totalDebt[borrowToken] -= amount;

        emit DebtRepaid(msg.sender, borrowToken, amount);
    }

    // ==================== View Functions ====================

    /**
     * @dev Get user's collateral value (mock - would integrate with price oracle)
     */
    function getCollateralValue(address user) public view returns (uint256) {
        uint256 totalValue = 0;

        for (uint256 i = 0; i < supportedCollaterals.length; i++) {
            address token = supportedCollaterals[i];
            uint256 amount = collateralDeposits[user][token];

            if (amount > 0) {
                // Simple value: 1 token = 1 unit (would use price oracle)
                totalValue += amount;
            }
        }

        return totalValue;
    }

    /**
     * @dev Get user's total debt value
     */
    function getTotalDebt(address user) public view returns (uint256) {
        uint256 debt = 0;

        for (uint256 i = 0; i < supportedCollaterals.length; i++) {
            address token = supportedCollaterals[i];
            debt += borrowedAmount[user][token];
        }

        return debt;
    }

    /**
     * @dev Calculate health factor
     * Health Factor = Collateral Value / Debt
     * If HF < Liquidation Threshold, position can be liquidated
     */
    function getHealthFactor(address user) public view returns (uint256) {
        uint256 collateralValue = getCollateralValue(user);
        uint256 debt = getTotalDebt(user);

        if (debt == 0) return type(uint256).max;

        return (collateralValue * 10000) / debt;
    }

    /**
     * @dev Check if position is healthy
     */
    function isHealthy(address user) public view returns (bool) {
        uint256 healthFactor = getHealthFactor(user);
        return healthFactor >= minCollateralRatio;
    }

    /**
     * @dev Check if position can be liquidated
     */
    function canBeLiquidated(address user) public view returns (bool) {
        uint256 healthFactor = getHealthFactor(user);
        return healthFactor < liquidationThreshold;
    }

    /**
     * @dev Get list of supported collaterals
     */
    function getSupportedCollaterals() external view returns (address[] memory) {
        return supportedCollaterals;
    }
}

